public class Customer { private final String customerId; private final String name; private final String email; public Customer(String id, String name, String email) { customerId=id; this.name=name; this.email=email; } public String getCustomerId() { return customerId; } public String getName() { return name; } public String getEmail() { return email; } public String toString() { return "Customer{id='" + customerId + "', name='" + name + "', email='" + email + "'}"; } }